  // src/pages/inbox.js
  function bleh_inbox() {
    page.structure.container = document.body.querySelector(".page-content");
    try {
      page.structure.row = page.structure.container.querySelector(".row");
      page.structure.main = page.structure.row.querySelector(".col-main");
      page.structure.side = page.structure.row.querySelector(".col-sidebar");
    } catch (e) {
      log("unable to find elements", "page structure");
    }
    let content_top = document.body.querySelector(".content-top");
    checkup_page_structure(false, content_top);
    log("status is", "page", "info", page);
    update_page();
    if (page.subpage == "notifications") {
      let form = page.structure.container.querySelector("form");
      let notifications = page.structure.container.querySelector(".inbox-notifications");
      let pagination = page.structure.container.querySelector(".pagination");
      let panel = document.createElement("section");
      panel.classList.add("inbox-panel", "notifications-panel");
      if (form)
        panel.appendChild(form);
      if (notifications)
        panel.appendChild(notifications);
      if (pagination)
        panel.appendChild(pagination);
      page.structure.main.appendChild(panel);
      if (!notifications) return;
      bleh_notification_list(notifications);
      return;
      let notif_links = notifications.querySelectorAll(".inbox-notifications__item-link");
      notif_links.forEach((notification) => {
        let link = notification.getAttribute("href");
        if (link.endsWith("/obsessions/set") || link.endsWith("/listening-report/month")) return;
        let avatar2 = notification.querySelector(".avatar");
        let name = notification.querySelector(".inbox-notifications__item-description strong");
        if (!name) return;
        let name_text = sanitise(return_name_from_avatar(avatar2.querySelector("img")));
        let badge = patch_avatar(avatar2, name_text);
        name.classList.add("notification-user-name", `user-status--bleh-${badge.type}`, `user-status--bleh-user-${name_text}`);
        if (notification.classList.contains("inbox-notifications__item--highlight"))
          notification.classList.add("notification-user-name", `user-status--bleh-${badge.type}`, `user-status--bleh-user-${name_text}`);
      });
    } else if (page.subpage == "message_overview" || page.subpage == "sent_message") {
      let inbox = page.structure.container.querySelector(".inbox-message-view");
      page.structure.main.appendChild(inbox);
      let sender_panel = inbox.querySelector(".inbox-message-sender-avatar");
      let sender_name = inbox.querySelector(".inbox-message-sender-name");
      let sender_time = inbox.querySelector(".inbox-message-timestamp");
      sender_panel.appendChild(sender_name);
      sender_panel.appendChild(sender_time);
      let avatar2 = sender_panel.querySelector(".avatar");
      let name_text = sanitise(sender_name.textContent.trim());
      let badge = patch_avatar(avatar2, name_text);
      sender_panel.classList.add(`user-status--bleh-${badge.type}`, `user-status--bleh-user-${name_text}`);
    } else if (page.subpage == "compose") {
      let inbox = page.structure.container.querySelector(".inbox-compose-view");
      page.structure.main.appendChild(inbox);
    } else {
      let inbox = page.structure.container.querySelector(".inbox");
      page.structure.main.appendChild(inbox);
    }
  }

  // src/pages/search.js
  async function bleh_search() {
    page.structure.container = document.body.querySelector(".page-content");
    try {
      page.structure.row = page.structure.container.querySelector(".row");
      page.structure.main = page.structure.row.querySelector(".col-main");
      page.structure.side = page.structure.row.querySelector(".col-sidebar");
    } catch (e) {
      log("unable to find elements", "page structure");
    }
    let content_top = document.body.querySelector(".content-top");
    let search_form = page.structure.main.querySelector(".search-form");
    let search = search_form.querySelector("#site-search");
    let value = search.getAttribute("value");
    if (!page.mobile) {
      let site_search = document.body.querySelector("#masthead-search-field");
      site_search.setAttribute("value", value);
      site_search.focus();
      page.structure.main.removeChild(search_form);
    }
    page.name = value != "" ? value : "empty..";
    checkup_page_structure(false, content_top);
    log("status is", "page", "info", page);
    update_page();
    if (page.subpage != "overview") {
      let new_panel = document.createElement("section");
      new_panel.classList.add("search-results-panel");
      let elements2 = page.structure.main.querySelectorAll(":scope > *:not(form)");
      elements2.forEach((element) => {
        new_panel.appendChild(element);
      });
      page.structure.main.appendChild(new_panel);
    }
    if (page.subpage == "overview" || page.subpage == "tracks") {
      patch_titles();
    }
    if (page.subpage == "artists" && settings.corrections) {
      let artists = page.structure.main.querySelectorAll(".artist-result-heading a");
      artists.forEach((artist) => {
        artist.textContent = correct_artist(artist.textContent);
      });
    }
    if (page.subpage == "albums") {
      let results = page.structure.main.querySelectorAll(".album-result-inner");
      results.forEach((result) => {
        let heading = result.querySelector(".album-result-heading a");
        let artist_parent = result.querySelector(".album-result-artist");
        let artist = artist_parent.querySelector("a");
        artist.textContent = correct_artist(artist.textContent);
        heading.textContent = correct_item_by_artist(heading.textContent, artist.textContent);
        let image = result.querySelector(".album-result-image");
        let image_parent = document.createElement("span");
        image_parent.classList.add("avatar", "album-result-image");
        image_parent.appendChild(image);
        image.classList = [];
        artist_parent.after(image_parent);
      });
    }
    page.structure.container.insertBefore(html.node`
        <section class="redesigned-header search-header no-background">
            <div class="tag-side">
                <div class="tag-icon search-icon"></div>
            </div>
            <div class="info-side">
                <div class="sub-text">${tl2(trans.search)}</div>
                <h1>${value}</h1>
            </div>
        </section>
    `, page.structure.container.firstElementChild);
    let cache2;
    if (auth.name) {
      cache2 = await load_profile_cache_externally(auth.name);
      if (cache2.banner)
        register_background(cache2.banner);
      else if (auth.avatar && !auth.avatar.endsWith("818148bf682d429dc215c1705eb27b98.png"))
        register_background(auth.avatar.replace("/avatar42s/", "/ar0/"));
      else
        register_background(null);
    } else {
      register_background(null);
    }
    if (!auth.pro) return;
    const nav_items = page.structure.nav.querySelector(".navlist-items");
    let explore;
    nav_items.appendChild(html.node`
        <li class="fill"></li>
        <li class="navlist-item secondary-nav-item secondary-nav-item--library">
            <a class="secondary-nav-item-link" ref=${(el) => explore = el}>
                ${tl2(trans.explore_in_library)}
            </a>
        </li>
    `);
    tippy_esm_default(explore, {
      content: html.node`
            <a class="dropdown-menu-clickable-item" data-type="artist" href="${root}user/${auth.name}/library/artists/search?query=${sanitise(value)}">
                ${tl2(trans.artists)}
            </a>
            <a class="dropdown-menu-clickable-item" data-type="album" href="${root}user/${auth.name}/library/albums/search?query=${sanitise(value)}">
                ${tl2(trans.albums)}
            </a>
            <a class="dropdown-menu-clickable-item" data-type="track" href="${root}user/${auth.name}/library/tracks/search?query=${sanitise(value)}">
                ${tl2(trans.tracks)}
            </a>
        `,
      theme: "menu",
      placement: "bottom",
      interactive: true,
      interactiveBorder: 10,
      trigger: "click",
      onShow(instance) {
        instance.popper.addEventListener("click", (event3) => {
          instance.hide();
        });
      }
    });
  }

  // src/rain.js
  function rain() {
    let rain_container = html.node`
        <div class="rain-container" />
    `;
    if (page.structure.rain) {
      rain_container = page.structure.rain;
      rain_container.remove();
    } else {
      page.structure.rain = rain_container;
    }
    let rain_main;
    let rain_back;
    render(rain_container, html`
        <div class="rain" ref=${(el) => rain_main = el} />
        <div class="rain rain-back" ref=${(el) => rain_back = el} />
    `);
    document.body.appendChild(rain_container);
    let increment = 0;
    let drops = "";
    let subtle_drops = "";
    while (increment < 60) {
      let randoms = [
        Math.floor(Math.random() * (98 - 1 + 1) + 1),
        Math.floor(Math.random() * (5 - 2 + 1) + 2)
      ];
      increment += randoms[1];
      drops += '<div class="drop" style="left: ' + increment + "%; bottom: " + (randoms[1] + randoms[1] - 1 + 280) + "%; animation-delay: 0." + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"><div class="stem" style="animation-delay: 0.' + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"></div><div class="splat" style="animation-delay: 0.' + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"></div></div>';
      subtle_drops += '<div class="drop" style="right: ' + increment + "%; bottom: " + (randoms[1] + randoms[1] - 1 + 280) + "%; animation-delay: 0." + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"><div class="stem" style="animation-delay: 0.' + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"></div><div class="splat" style="animation-delay: 0.' + randoms[0] + "s; animation-duration: 0.5" + randoms[0] + 's;"></div></div>';
      rain_main.innerHTML = drops;
      rain_back.innerHTML = subtle_drops;
    }
  }
  function start_rain() {
    if (settings.rain) rain();
  }

  // src/shout.js
  function patch_shouts() {
    if (!page.structure.main) return;
    let shout_controls = page.structure.main.querySelector(
      ".shoutbox-controls-wrapper:not([data-shouts])"
    );
    if (shout_controls) {
      shout_controls.setAttribute("data-shouts", "true");
      shout_header(shout_controls);
    }
    let shouts = page.structure.main.querySelectorAll(
      ".shout:not([data-kate-processed])"
    );
    shouts.forEach((shout, index3) => {
      try {
        let vote_button = function() {
          setTimeout(() => {
            const modified = form.getAttribute("data-ajax-form-state") == "modified-state";
            const current_is_voted = initial_is_voted != modified;
            indicator.setAttribute(
              "aria-checked",
              current_is_voted.toString()
            );
          }, 0);
        };
        shout.setAttribute("data-kate-processed", "true");
        shout.style.setProperty("--delay", index3 * 0.04 + "s");
        let shout_name = shout.querySelector(".shout-user a");
        if (!shout_name) return;
        let shout_name_text = shout_name.textContent;
        let shout_avatar = shout.querySelector(".shout-user-avatar");
        let badge = patch_avatar(shout_avatar, shout_name_text, "shout");
        if (badge) {
          if (badge.type && badge.type == "avatar-status-dot--staff")
            shout.classList.add("staff-shout");
          style_name_from_badge(shout_name, badge);
        }
        const shout_body = shout.querySelector(".shout-body p");
        const shout_text = shout_body.textContent.trim();
        if (settings.shout_markdown) {
          shout_parse_queue.push({ element: shout_body });
        }
        const indicator = html.node`
                <div class="shout-vote-indicator colourful" aria-checked="false" />
            `;
        shout.appendChild(indicator);
        let shout_timestamp = shout.querySelector(".shout-timestamp time");
        if (shout_timestamp) {
          tippy_esm_default(shout_timestamp, {
            content: shout_timestamp.getAttribute("title")
          });
          shout_timestamp.removeAttribute("title");
        }
        let actions = shout.querySelectorAll(
          ".shout-actions .shout-action"
        );
        actions.forEach((action) => {
          let buttons2 = action.querySelectorAll("button, a");
          buttons2.forEach((button) => {
            button.classList.add("shout-action-button", "see-more");
          });
        });
        const form = shout.querySelector(".vote-button-toggle");
        const voted_button = form.querySelector(".vote-button--voted");
        const unvote_button = form.querySelector(
          ".vote-button:not(.vote-button--voted)"
        );
        if (!voted_button || !unvote_button) return;
        const initial_is_voted = voted_button.getAttribute("data-ajax-form-sets-state") == "modified-state";
        indicator.setAttribute("aria-checked", initial_is_voted.toString());
        voted_button.addEventListener("click", (e) => vote_button());
        unvote_button.addEventListener("click", (e) => vote_button());
        const menu = shout.querySelector(".shout-more-actions-menu");
        const buttons = menu.querySelectorAll("button");
        buttons.forEach((button) => {
          const type = button.classList[1];
          if (type == "more-item--delete") {
            button.textContent = tl2(trans.delete);
          } else if (type == "more-item--report") {
            button.textContent = tl2(trans.report);
          }
        });
        menu.insertBefore(
          html.node`
                <button class="dropdown-menu-clickable-item" data-type="copy" onclick=${() => {
            copy(shout_text);
          }}>
                    ${tl2(trans.copy)}
                </button>
                <div class="sep" />
            `,
          menu.firstElementChild
        );
        let send_button = shout.querySelector(".form-group--submit");
        shout_send(send_button);
      } catch (e) {
        notify({
          id: "shout",
          title: tl2(trans.shouts),
          body: "Failed to be modified :(",
          type: "error",
          icon: "icon-16-shoutbox"
        });
        log("failed to modify", "shout", "error", { error: e });
      }
    });
    if (settings.shout_markdown && shout_parse_queue.length > 0)
      parse_shout_queue();
    const shout_forms = document.querySelectorAll(
      ".shout-form:not([data-kate-processed])"
    );
    shout_forms.forEach((shout_form) => {
      shout_form.setAttribute("data-kate-processed", "true");
      let shout_avatar = shout_form.querySelector(".shout-user-avatar");
      patch_avatar(shout_avatar, auth.name);
      let send_button = shout_form.querySelector(".form-group--submit");
      shout_send(send_button);
      const help_text = shout_form.querySelector(".form-row-help-text");
      help_text.classList.add("dual-tip");
      const textarea = shout_form.querySelector("textarea");
      let chars;
      let preview;
      render(
        help_text,
        html`
                <div
                    class="tip markdown-enabled"
                    onclick=${() => markdown_prompt()}
                >
                    ${tl2(trans.supports_markdown)}
                </div>
                <div
                    class="tip preview"
                    onclick=${() => markdown_preview(textarea.value)}
                    ref=${(el) => preview = el}
                    disabled="true"
                >
                    ${tl2(trans.preview)}
                </div>
                <div class="tip characters" ref=${(el) => chars = el}>
                    ${tl2(trans.value_characters_max, { v: "0/1000" })}
                </div>
            `
      );
      textarea.addEventListener("input", () => {
        const value = textarea.value;
        chars.textContent = tl2(trans.value_characters_max, {
          v: `${value.length}/1000`
        });
        chars.setAttribute("data-exceeded", value.length >= 1e3);
        preview.setAttribute("disabled", value.length <= 0);
      });
      shout_form.addEventListener("keydown", (e) => {
        if (e.ctrlKey && e.keyCode == 13) {
          e.preventDefault();
          send_button.querySelector(".btn-post-shout").click();
          notify({
            id: "shout",
            title: tl2(trans.shouts),
            body: tl2(trans.sent),
            icon: "icon-16-shoutbox"
          });
        }
      });
    });
  }
  function shout_send(send_button) {
    if (!send_button) return;
    let button = send_button.querySelector(".btn-post-shout");
    if (!button) return;
    button.classList.add("btn-send-shout-generic");
    button.textContent = tl2(trans.send);
    if (page.mobile) return;
    tippy_esm_default(button, {
      content: tl2(trans.send_quickly_with).replace(
        "{kbd}",
        keybind(["\u2318", "\u23CE"]).outerHTML
      ),
      allowHTML: true,
      delay: [500, 0]
    });
  }
  function shout_header(shout_controls) {
    let panel;
    let settings_btn;
    if (page.subpage == "shoutbox_shout") {
      panel = page.structure.main.querySelector(":scope > section");
      let link = window.location.href;
      panel.insertBefore(
        html.node`
            <div class="top-container">
                <h2>
                    <a class="text-colour-link" href=${link}>${tl2(trans.shouts)}</a>
                </h2>
                <div class="accompany view-buttons blend blend-v2">
                    <p class="notice">${tl2(trans.single_shout)}</p>
                </div>
                <div class="view-buttons blend blend-v2">
                    <button class="left-icon blend-v2-btn" data-type="settings" ref=${(el) => settings_btn = el}>
                        ${tl2(trans.settings)}
                    </button>
                </div>
            </div>
        `,
        panel.firstElementChild
      );
    } else if (shout_controls) {
      panel = shout_controls.parentElement;
      let select_btn = panel.querySelector(".dropdown-menu-clickable-button");
      let header = panel.querySelector("h2");
      if (header) header.parentElement.removeChild(header);
      let link = window.location.href;
      let shoutbox_link = "+shoutbox";
      if (page.type == "user" || page.type == "event")
        shoutbox_link = "shoutbox";
      if (!page.subpage.startsWith("shoutbox")) link += `/${shoutbox_link}`;
      panel.insertBefore(
        html.node`
            <div class="top-container">
                <h2>
                    <a class="text-colour-link" href=${link}>${tl2(trans.shouts)}</a>
                </h2>
                ${select_btn ? html.node`
                    <div class="accompany view-buttons blend blend-v2">
                        ${() => {
          select_btn.classList.add(
            "select-button",
            "link-select",
            "blend-v2-btn"
          );
          select_btn.classList.remove(
            "section-control",
            "dropdown-menu-clickable-button"
          );
          return shout_controls;
        }}
                    </div>
                ` : ""}
                <div class="view-buttons blend blend-v2">
                    <button class="left-icon blend-v2-btn" data-type="settings" ref=${(el) => settings_btn = el}>
                        ${tl2(trans.settings)}
                    </button>
                </div>
            </div>
        `,
        panel.firstElementChild
      );
    }
    if (!settings_btn) return;
    tippy_esm_default(settings_btn, {
      theme: "window",
      content: html.node`
            <div class="dialog-settings">
                <div class="setting-group blend">
                    ${setting({ id: "shout_markdown" })}
                    ${setting({ id: "accessible_name_colours" })}
                    ${setting({ id: "underline_links" })}
                </div>
            </div>
        `,
      placement: "bottom",
      interactive: true,
      interactiveBorder: 10,
      trigger: "click",
      appendTo: document.body
    });
    const cant_shout = panel.querySelector(".shouting-unavailable");
    if (cant_shout) {
      render(
        cant_shout,
        html`
                <div class="loading-data-container">
                    <div class="loading-data-text static" data-type="shouts">
                        ${tl2(trans.cant_shout)}
                    </div>
                </div>
            `
      );
    }
  }
  function parse_shout_queue() {
    if (shout_parse_queue.length === 0) return;
    const shout = shout_parse_queue.shift();
    const parsed2 = markdown(shout.element.textContent);
    shout.element.classList.add("markdown-body");
    render(shout.element, html.node`${parsed2}`);
    log("parsed one shout", "shout", "log");
    if (shout_parse_queue.length > 0) setTimeout(parse_shout_queue, 50);
  }
  function shout_messages() {
    if (!page.structure.main) return;
    let alerts = page.structure.main.querySelectorAll(
      ".shout-messages > .alert"
    );
    alerts.forEach((alert2) => {
      if (alert2.classList.contains("alert-danger")) {
        notify({
          id: "shout",
          title: tl2(trans.shouts),
          body: tl2(trans.failed_to_send),
          type: "error",
          icon: "icon-16-shoutbox"
        });
      } else {
        return;
      }
      alert2.remove();
    });
  }

  // src/components/radio.js
  function bleh_radio() {
    let radios = page.structure.side.querySelectorAll(".stationlink");
    radios.forEach((radio2) => {
      let type = radio2.getAttribute("data-analytics-label");
      radio2.classList.add("radio-button");
      let text3 = tl2(trans[type]);
      if (type == "tag")
        text3 = page.name;
      else if (type == "event")
        text3 = tl2(trans.artists);
      render(radio2, html`
            <h3 class="sub-text">${tl2(trans.radio)}</h3>
            <h4>${text3}</h4>
        `);
      radio2.removeAttribute("title");
    });
    if (page.type == "user") {
      let promo_v3 = page.structure.side.querySelector(".promo-v3");
      if (!promo_v3) return;
      let header = promo_v3.querySelector("h2");
      header.textContent = tl2(trans.listening);
      let promos = promo_v3.querySelectorAll(".listening-report-promo");
      let container = document.createElement("div");
      container.classList.add("listening-report-promos");
      promos.forEach((promo) => {
        container.appendChild(promo);
      });
      promo_v3.appendChild(container);
      if (radios.length == 0) return;
      let sep = document.createElement("div");
      sep.classList.add("sep");
      promo_v3.appendChild(sep);
      let list = page.structure.side.querySelector(".stationlink-list");
      page.structure.side.removeChild(list.parentElement);
      promo_v3.appendChild(list);
    } else {
      let header = page.structure.side.querySelector(".stationlinks-header");
      header.textContent = tl2(trans.listening);
    }
  }

  // src/pages/api.js
  async function bleh_api() {
    if (page.subpage == "docs") return;
    page.structure.container = document.body.querySelector(".page-content");
    try {
      page.structure.row = page.structure.container.querySelector(".row");
      page.structure.main = page.structure.row.querySelector(".col-main");
      page.structure.side = page.structure.row.querySelector(".col-sidebar");
    } catch (e) {
      log("unable to find elements", "page structure");
    }
    let content_top = document.body.querySelector(".content-top");
    checkup_page_structure(false, content_top);
    log("status is", "page", "info", page);
    update_page();
    const cache2 = await load_profile_cache_externally(auth.name);
    if (cache2.banner)
      register_background(cache2.banner);
    else if (!auth.avatar.endsWith("818148bf682d429dc215c1705eb27b98.png"))
      register_background(auth.avatar.replace("/avatar42s/", "/ar0/"));
    else
      register_background(null);
    if (page.subpage == "create_account") return;
    page.structure.container.removeAttribute("data-beret");
    page.structure.container.removeAttribute("data-short");
    page.structure.content.classList.add("cards-view");
    let success = page.structure.container.querySelector(".alert-success");
    if (!success) {
      let old = page.structure.main.querySelector("section");
      if (!old) return;
      page.name = old.querySelector(".api-app-name").textContent;
      let description = old.querySelector(".api-app-description").textContent.trim();
      let token = old.querySelector('form [name="csrfmiddlewaretoken"]').value;
      let cancel = old.querySelector(".form-submit a").getAttribute("href");
      render(page.structure.main, html`
            <section class="api-connector sour">
                <div class="avatar">
                    <img src="${auth.avatar.replace("/avatar42s/", "/avatar170s/")}" alt="${tl2(trans.your_avatar)}">
                </div>
                <div class="info">
                    <h1>${page.name}</h1>
                    <div class="sub-text no-margin">${tl2(trans.app_would_like_to_connect)}</div>
                    <div class="subtle">
                        ${html.node([
        tl2(trans.logged_in_as).replace("{user}", `<a class="mention" href="${root}user/${auth.name}">@${auth.name}</a>`)
      ])}
                    </div>
                </div>
                <div class="sep"></div>
                <div class="description">${description}</div>
                <div class="small-label with-icon lock">${tl2(trans.ensure_you_trust)}</div>
                <div class="connector-footer">
                    <a class="see-more cancel" href="${cancel}">
                        ${tl2(trans.cancel)}
                    </a>
                    <form method="post" data-no-partial-refresh="">
                        <input type="hidden" name="csrfmiddlewaretoken" value="${token}">
                        <input type="hidden" name="confirmation" value="confirm">
                        <button class="btn primary icon connect" type="submit" name="confirm">
                            ${tl2(trans.connect)}
                        </button>
                    </form>
                </div>
            </section>
        `);
    } else {
      page.name = success.querySelector("strong").textContent;
      render(page.structure.main, html`
            <section class="api-connector sour">
                <div class="avatar">
                    <img src="${auth.avatar.replace("/avatar42s/", "/avatar170s/")}" alt="${tl2(trans.your_avatar)}">
                </div>
                <div class="info">
                    <h1>${page.name}</h1>
                    <div class="sub-text no-margin">${tl2(trans.has_been_connected)}</div>
                </div>
                <div class="sep"></div>
                <div class="description">${tl2(trans.you_can_now_close_this_tab)}</div>
                <div class="connector-footer">
                    <div class="btn-fill"/>
                    <a class="see-more" href="${root}settings/applications">
                        ${tl2(trans.manage_applications)}
                    </a>
                    <div class="btn-fill"/>
                </div>
            </section>
        `);
    }
  }

  // src/pages/users.js
  function bleh_users() {
    const users = page.structure.main?.querySelectorAll(".user-list-item:not(.user-list-item-mobile-ad)");
    users.forEach((user) => {
      let avatar2 = user.querySelector(".user-list-avatar");
      let name = user.querySelector(".user-list-link");
      const badge = patch_avatar(avatar2, name.textContent, "follow");
      style_name_from_badge(name, badge);
      let artists = user.querySelectorAll(".user-list-shared-artists a");
      artists.forEach((artist) => {
        artist.textContent = correct_artist(artist.textContent);
      });
      const md = user.querySelector(".user-list-about-me");
      log("patching", "user", "info", { user, name: name?.textContent, md });
      if (md) {
        render(
          md,
          markdown(md.textContent, {
            allow_headers: false,
            line_breaks: false,
            allow_lists: false
          })
        );
      }
    });
  }

