  // src/components/dialog_extender.js
  function dialog_extender() {
    log("dialog extender", "loop");
    let wrappers = document.body.querySelectorAll(
      ":scope > .popup_wrapper, :scope > div > .popup_wrapper"
    );
    wrappers.forEach((wrapper) => {
      let modal_dialog = wrapper.querySelector(
        ".modal-dialog:not([data-dialog-extender])"
      );
      if (!modal_dialog) return;
      modal_dialog.setAttribute("data-dialog-extender", "true");
      let body = modal_dialog.querySelector(".modal-body");
      let title = body.querySelector(".modal-title");
      let contents = body.querySelector(":scope > div");
      let form = contents.querySelector("form");
      if (!form) return;
      let dismiss = modal_dialog.querySelector(".modal-dismiss");
      let token = form.querySelector('[name="csrfmiddlewaretoken"]');
      if (token) page.token = token.getAttribute("value");
      if (form.action && form.action.endsWith("+bookmarks/modal/added")) {
        title.textContent = tl2(trans.saved_to_bookmarks);
        let new_form;
        render(
          contents,
          html`
                    <div class="big-modal-alert">
                        ${{
            html: tl2(trans.bookmark_save_msg).replace(
              "{link}",
              `<a class="see-more" href="${root}music/+bookmarks">${tl2(trans.go_there_now_lower)}</a>`
            )
          }}
                    </div>
                    <form
                        method="post"
                        ref=${(el) => new_form = el}
                        onsubmit=${async (e) => {
            e.preventDefault();
            let url = `${root}music/+bookmarks/modal/added`;
            let form_data = new FormData(new_form);
            console.info(form_data);
            try {
              await fetch(url, {
                method: "POST",
                body: form_data
              }).then((res) => {
                let data2 = res.json();
                log("received response", "form", "info", {
                  data: data2
                });
                dismiss.click();
              });
            } catch (e2) {
              console.error(e2);
            }
          }}
                    >
                        <input
                            type="hidden"
                            name="csrfmiddlewaretoken"
                            value="${page.token}"
                        />
                        <div class="modal-footer">
                            ${toggle({
            value: true,
            type: "checkbox",
            name: "always_show",
            title: tl2(trans.always_remind_me)
          })}
                            <button class="btn primary done" type="submit">
                                ${tl2(trans.done)}
                            </button>
                        </div>
                    </form>
                `
        );
      } else if (body.classList.contains("automatic-edit-modal-body-v2")) {
        let bulk_edit_active = false;
        let edit_all = body.querySelector('[name="edit_all"]');
        if (edit_all && edit_all.disabled) bulk_edit_active = true;
        if (!bulk_edit_active) title.textContent = tl2(trans.edit_scrobble);
        else title.textContent = tl2(trans.edit_scrobbles_in_bulk);
        modal_dialog.classList.add("automatic-edit-modal");
        let checkboxes = body.querySelectorAll(".checkbox");
        checkboxes.forEach((checkbox) => {
          let input_el = checkbox.querySelector("input");
          let value = input_el.checked;
          let name = input_el.getAttribute("name");
          let text3 = checkbox.textContent.trim();
          let disabled = input_el.disabled;
          render(
            checkbox.parentElement,
            html`
                        ${toggle({
              value,
              type: "checkbox",
              name,
              title: text3,
              disabled,
              data: input_el.value
            })}
                    `
          );
        });
        let original_fields = body.querySelectorAll(
          ".edit-scrobble-label--originally"
        );
        original_fields.forEach((field) => {
          field.textContent = field.textContent.trim().replace(/"([^"]*)"/g, "\u2018$1\u2019");
        });
        let submit = body.querySelector(".form-group--submit");
        submit.classList = "modal-footer";
        let delete_form = body.querySelector(".edit-scrobble-form-delete");
        let delete_btn;
        if (delete_form)
          delete_btn = delete_form.querySelector(".btn-delete");
        render(
          submit,
          html`
                    <button
                        class="see-more cancel"
                        type="button"
                        onclick=${() => dismiss.click()}
                    >
                        ${tl2(trans.cancel)}
                    </button>
                    <div class="fill" />
                    <div class="button-group">
                        ${delete_form ? html.node`
                    <button class="btn icon danger-subtle" data-type="delete" type="button" onclick=${() => {
            delete_btn.click();
          }}>
                        ${tl2(trans.delete)}
                    </button>
                    ` : ""}
                        ${submit.querySelector("input")}
                        <button
                            class="btn primary icon"
                            data-type="item-edit"
                            type="submit"
                        >
                            ${tl2(trans.edit)}
                        </button>
                    </div>
                `
        );
      } else if (body.querySelector(".lastfm-bulk-edit-list")) {
        let checks;
        let controls = body.querySelector(
          ".lastfm-bulk-edit-form-group-controls"
        );
        if (controls) {
          let parent = controls.parentElement;
          parent.parentElement.removeChild(parent);
          let disclaimer = body.querySelector(".form-disclaimer");
          disclaimer.after(html.node`
                    <div class="button-group">
                        <button class="flex-button" onclick=${() => {
            checks.forEach((check) => {
              check.check();
            });
          }} type="button">
                            <div class="bleh-icon" data-type="select-all" style="--icon: var(--mask)" />
                            ${tl2(trans.select_all)}
                        </button>
                        <button class="flex-button" onclick=${() => {
            checks.forEach((check) => {
              check.uncheck();
            });
          }} type="button">
                            <div class="bleh-icon" data-type="deselect-all" style="--icon: var(--mask)" />
                            ${tl2(trans.deselect_all)}
                        </button>
                    </div>
                `);
        }
        let list = body.querySelector(".lastfm-bulk-edit-list");
        let checkboxes = list.querySelectorAll(".checkbox");
        checkboxes.forEach((checkbox) => {
          let input_el = checkbox.querySelector("input");
          let value = input_el.checked;
          let name = input_el.getAttribute("name");
          let disabled = input_el.disabled;
          let data2 = input_el.getAttribute("value");
          let item_artist = correct_artist(
            checkbox.querySelector("div").title
          );
          let item_name = correct_item_by_artist(
            checkbox.querySelector("strong").title,
            item_artist
          );
          let item_scrobbles = checkbox.querySelector("small").textContent.trim();
          render(
            checkbox.parentElement,
            html`
                        ${toggle({
              value,
              type: "checkbox",
              name,
              title: item_name + tl2(trans.by_artist).replace("{a}", item_artist),
              body: item_scrobbles,
              disabled,
              data: data2
            })}
                    `
          );
        });
        checks = list.querySelectorAll(".setting");
        let footer = body.querySelector(".form-group--submit");
        footer.classList = "modal-footer";
        render(
          footer,
          html`
                    <button class="see-more cancel" type="reset">
                        ${tl2(trans.cancel)}
                    </button>
                    <div class="fill" />
                    <button class="btn primary continue" type="submit">
                        ${tl2(trans.continue)}
                    </button>
                `
        );
      }
    });
  }

  // src/pages/auth.js
  async function bleh_auth() {
    page.structure.container = document.body.querySelector(".page-content");
    try {
      page.structure.row = page.structure.container.querySelector(".row");
      page.structure.main = page.structure.row.querySelector(".col-main");
      page.structure.side = page.structure.row.querySelector(".col-sidebar");
    } catch (e) {
      log("unable to find elements", "page structure");
    }
    checkup_page_structure();
    const cache2 = await load_profile_cache_externally(auth.name);
    if (cache2.banner) register_background(cache2.banner);
    else if (!auth.avatar.endsWith("818148bf682d429dc215c1705eb27b98.png"))
      register_background(auth.avatar.replace("/avatar42s/", "/ar0/"));
    else register_background(null);
    page.type = "bleh_auth";
    page.subpage = "";
    log("status is", "page", "info", page);
    update_page();
    page.structure.row.removeChild(page.structure.row.firstElementChild);
    page.structure.row.removeChild(page.structure.row.firstElementChild);
    page.structure.container.removeAttribute("data-beret");
    page.structure.container.removeAttribute("data-short");
    page.structure.content.classList.add("cards-view");
    if (!page.requested.token) {
      render(
        page.structure.main,
        html`
                <section class="api-connector sour">
                    <div class="loading-data-container">
                        <div class="loading-data-text error">
                            ${tl2(trans.no_token_provided)}
                        </div>
                    </div>
                </section>
            `
      );
      return;
    }
    render(
      page.structure.main,
      html`
            <section class="api-connector sour">
                <div class="loading-data-container">
                    <div class="loading-data-text">${tl2(trans.loading)}</div>
                </div>
            </section>
        `
    );
    const res = await fetch("https://jufufu.katelyn.moe/api/lastfm", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        method: "auth.getSession",
        params: { token: page.requested.token }
      })
    });
    const json = await res.json();
    if (json.error) {
      log("error", "auth", "error", json);
      render(
        page.structure.main,
        html`
                <section class="api-connector sour">
                    <div class="loading-data-container">
                        <div class="loading-data-text error">
                            ${json.message}
                        </div>
                    </div>
                </section>
            `
      );
      return;
    }
    const { name, key } = json.session;
    log(`authorised as ${name}`, "auth", "info", json.session);
    set_storage("bleh_auth", key);
    set_storage("bleh_auth_valid", "true");
    render(
      page.structure.main,
      html`
            <section class="api-connector sour">
                <div class="avatar">
                    <img
                        src="${auth.avatar.replace(
        "/avatar42s/",
        "/avatar170s/"
      )}"
                        alt="${tl2(trans.your_avatar)}"
                    />
                </div>
                <div class="info">
                    <h1>bleh</h1>
                    <div class="sub-text no-margin">
                        ${tl2(trans.has_been_connected)}
                    </div>
                </div>
                <div class="sep"></div>
                <div class="description">
                    ${tl2(trans.you_can_now_close_this_tab)}
                </div>
                <div class="connector-footer">
                    <div class="btn-fill" />
                    <a class="btn primary continue" href="${root}bleh">
                        ${tl2(trans.continue)}
                    </a>
                    <div class="btn-fill" />
                </div>
            </section>
        `
    );
  }

  // src/pages/labs.js
  function bleh_labs() {
    if (page.subpage != "overview") return;
    let quilt = document.body.querySelector(
      '[data-analytics-action="LaunchAlbumQuilt"]'
    );
    if (quilt) {
      page.avatar = auth.avatar;
      page.name = auth.name;
      quilt.setAttribute("href", `${root}bleh/minis/collage?redirect=true`);
      quilt.removeAttribute("target");
    }
  }

  // src/pages/mualani.js
