  function tl2(key, replacements = {}) {
    if (!key) {
      log("your key is undefined", "trans");
      return "NO_TRANSLATION_FOUND";
    }
    let translation = key[lang] || key.en;
    for (const [placeholder, value] of Object.entries(replacements)) {
      const regex = new RegExp(`{${placeholder}}`, "g");
      translation = translation.replace(regex, value);
    }
    return translation;
  }
  function collect_keys(object, prefix, out = []) {
    for (const k in object) {
      const val = object[k];
      const key = prefix ? `${prefix}.${k}` : k;
      if (typeof val == "object" && !Object.keys(lang_info).some((lang2) => lang2 in val)) {
        collect_keys(val, key, out);
      } else {
        out.push(key);
      }
    }
    return out;
  }
  function get_value_by_path(object, path) {
    return path.split(".").reduce((acc, part) => acc?.[part], object);
  }
  function translation_stats() {
    const keys2 = collect_keys(trans);
    for (const lang2 of Object.keys(lang_info)) {
      let translated = 0;
      const missing = [];
      for (const key of keys2) {
        const value = get_value_by_path(trans, key);
        if (value && value[lang2]) {
          translated++;
        } else {
          missing.push(key);
        }
      }
      lang_info[lang2].total = keys2.length;
      lang_info[lang2].translated = translated;
      lang_info[lang2].missing = missing.length;
      lang_info[lang2].missing_keys = missing;
      lang_info[lang2].percent = Math.round(translated / keys2.length * 100);
    }
    log("translation stats", "trans", "info", { lang_info });
  }
  function get_lang() {
    const path = window.location.pathname;
    const segments = path.split("/");
    const lang2 = segments[1];
    if (/^[a-z]{2}$/.test(lang2)) {
      return `/${lang2}/`;
    }
    return "/";
  }
  function lookup_lang() {
    const logo = document.querySelector(".masthead-logo a");
    if (!logo) {
      handle_error_500();
      return;
    }
    setRoot(get_lang());
    let previous_avi = auth.avatar;
    if (auth_link.state) {
      auth.avatar = auth_link.state.querySelector("img").getAttribute("src");
      if (auth.avatar != previous_avi) {
        let avatar2 = auth_link.state.querySelector("img");
        avatar2.setAttribute("crossorigin", "anonymous");
        try {
          avatar2.addEventListener("load", () => {
            let thief = new import_color_thief_browser3.default();
            let colour2 = thief.getColor(avatar2);
            let hsl = rgb_to_hsl(colour2[0], colour2[1], colour2[2]);
            auth.sets.hue = hsl.h;
            auth.sets.sat = clamp_sat2(hsl.s / 100 * 3);
            auth.sets.lit = clamp_lit(auth.sets.sat, hsl.l / 100 + 0.35);
          });
        } catch (e) {
        }
      }
    }
    lang = document.documentElement.getAttribute("lang");
    Settings.defaultLocale = lang;
  }

