  // src/build/log.js
  function log(text3, system, type = "info", append = {}) {
    if (!page.structure.logs) {
      let logs = html.node`<div class="logs">
            <div class="setting" data-type="toggle" id="container-log_show_all" onclick="_update_item('log_show_all')">
                <div class="toggle-wrap">
                    <button id="toggle-log_show_all">
                        show all
                    </button>
                </div>
            </div>
        </div>`;
      document.documentElement.appendChild(logs);
      page.structure.logs = logs;
    }
    let system_colour;
    switch (system) {
      case "load":
        system_colour = "#8CB9D9";
        break;
      case "lotus":
        system_colour = "#8CD9A6";
        break;
      case "season":
        system_colour = "#65B6D8";
        break;
      case "page":
        system_colour = "#E4B381";
        break;
      case "page structure":
        system_colour = "#D88A69";
        break;
      case "style":
        system_colour = "#C9C678";
        break;
      case "profile":
        system_colour = "#D56854";
        break;
      case "settings":
        system_colour = "#6D6977";
        break;
      case "sponsor":
        system_colour = "#CE4E88";
        break;
      default:
        system_colour = "#C8DD88";
        break;
    }
    if (Object.keys(append).length > 0)
      console[type](`%c${system}%c ${text3}`, `background: ${system_colour}; display: block; width: fit-content; font-weight: bold; color: #000; padding: 0 4px; border-radius: 4px`, "color: unset", append);
    else
      console[type](`%c${system}%c ${text3}`, `background: ${system_colour}; display: block; width: fit-content; font-weight: bold; color: #000; padding: 0 4px; border-radius: 4px`, "color: unset");
    if (settings && settings.feature_flags) {
      if (settings.feature_flags.developer == true) {
        page.structure.logs.appendChild(
          html.node`
            <div class="log" data-type=${type}>
                <span class="system" style="color: ${system_colour}">${system}</span>
                <span class="text">${text3}</span>
            </div>`
        );
      }
    }
  }

